@dataclass
class FetchResult:
    url: str
    status_code: Optional[int]
    headers: Dict[str, str]
    text: str
    bytes: bytes
    elapsed_ms: int
    error: Optional[str] = None


_DEFAULT_ALLOWED_SCHEMES = ("https", "http")
_DEFAULT_TIMEOUT = (5.0, 15.0)  # (connect, read)
_DEFAULT_MAX_BYTES = 2 * 1024 * 1024
_DEFAULT_USER_AGENT = "WebhookFetcher/1.0"
_DEFAULT_MAX_REDIRECTS = 5


def _build_session(
    retries_total: int = 2,
    backoff_factor: float = 0.4,
    status_forcelist: Tuple[int, ...] = (429, 500, 502, 503, 504),
    allowed_methods: Tuple[str, ...] = ("GET", "HEAD"),
) -> requests.Session:
    sess = requests.Session()
    retry = Retry(
        total=retries_total,
        connect=retries_total,
        read=retries_total,
        status=retries_total,
        backoff_factor=backoff_factor,
        status_forcelist=status_forcelist,
        allowed_methods=set(allowed_methods),
        raise_on_status=False,
        respect_retry_after_header=True,
    )
    adapter = HTTPAdapter(max_retries=retry, pool_connections=32, pool_maxsize=64)
    sess.mount("http://", adapter)
    sess.mount("https://", adapter)
    return sess


def _is_ip_private_or_disallowed(ip_str: str) -> bool:
    try:
        ip = ipaddress.ip_address(ip_str)
    except ValueError:
        return True
    return (
        ip.is_private
        or ip.is_loopback
        or ip.is_link_local
        or ip.is_multicast
        or ip.is_reserved
        or ip.is_unspecified
    )


def _sanitize_url(
    url: str,
    allowed_schemes: Iterable[str] = _DEFAULT_ALLOWED_SCHEMES,
    strip_userinfo: bool = True,
) -> str:
    url = (url or "").strip()
    if not url:
        raise ValueError("Empty URL")

    p = urlparse(url)
    if not p.scheme:
        raise ValueError("URL must include scheme (http/https)")

    scheme = p.scheme.lower()
    if scheme not in set(s.lower() for s in allowed_schemes):
        raise ValueError(f"Disallowed URL scheme: {p.scheme}")

    if not p.netloc:
        raise ValueError("URL must include host")

    netloc = p.netloc
    if strip_userinfo and ("@" in netloc):
        netloc = netloc.split("@", 1)[1]

    if netloc.startswith("[") and "]" in netloc:
        host = netloc[1:netloc.index("]")]
        if _is_ip_private_or_disallowed(host):
            raise ValueError("Disallowed IP address host")
    else:
        host = netloc.split(":", 1)[0]
        try:
            ipaddress.ip_address(host)
            if _is_ip_private_or_disallowed(host):
                raise ValueError("Disallowed IP address host")
        except ValueError:
            pass

    sanitized = urlunparse((scheme, netloc, p.path or "/", p.params, p.query, ""))
    return sanitized


def fetch_url_content(
    url: str,
    *,
    method: str = "GET",
    headers: Optional[Dict[str, str]] = None,
    timeout: Tuple[float, float] = _DEFAULT_TIMEOUT,
    max_bytes: int = _DEFAULT_MAX_BYTES,
    allow_redirects: bool = True,
    max_redirects: int = _DEFAULT_MAX_REDIRECTS,
    allowed_schemes: Iterable[str] = _DEFAULT_ALLOWED_SCHEMES,
    user_agent: str = _DEFAULT_USER_AGENT,
    verify_tls: bool = True,
    session: Optional[requests.Session] = None,
) -> FetchResult:
    start = time.time()
    method_u = (method or "GET").upper()
    if method_u not in ("GET", "HEAD"):
        raise ValueError("Only GET/HEAD supported for content fetch")

    sanitized_url = _sanitize_url(url, allowed_schemes=allowed_schemes)

    req_headers = {"User-Agent": user_agent, "Accept": "*/*"}
    if headers:
        req_headers.update(headers)

    sess = session or _build_session()
    resp = None
    buf = bytearray()
    err = None
    status_code = None
    out_headers: Dict[str, str] = {}
    text = ""

    try:
        resp = sess.request(
            method_u,
            sanitized_url,
            headers=req_headers,
            timeout=timeout,
            allow_redirects=allow_redirects,
            stream=True,
            verify=verify_tls,
        )

        if allow_redirects and hasattr(resp, "history") and len(resp.history) > max_redirects:
            raise ValueError("Too many redirects")

        status_code = resp.status_code
        out_headers = {k: v for k, v in resp.headers.items()}

        if method_u == "HEAD":
            content = b""
        else:
            total = 0
            for chunk in resp.iter_content(chunk_size=8192):
                if not chunk:
                    continue
                total += len(chunk)
                if total > max_bytes:
                    raise ValueError("Response exceeded max_bytes limit")
                buf.extend(chunk)
            content = bytes(buf)

        if content:
            encoding = resp.encoding or "utf-8"
            try:
                text = content.decode(encoding, errors="replace")
            except Exception:
                text = content.decode("utf-8", errors="replace")
        else:
            text = ""

        elapsed_ms = int((time.time() - start) * 1000)
        return FetchResult(
            url=str(resp.url) if resp is not None else sanitized_url,
            status_code=status_code,
            headers=out_headers,
            text=text,
            bytes=content,
            elapsed_ms=elapsed_ms,
            error=None,
        )
    except Exception as e:
        err = str(e)
        elapsed_ms = int((time.time() - start) * 1000)
        return FetchResult(
            url=sanitized_url,
            status_code=status_code,
            headers=out_headers,
            text=text,
            bytes=bytes(buf),
            elapsed_ms=elapsed_ms,
            error=err,
        )
    finally:
        if resp is not None:
            try:
                resp.close()
            except Exception:
                pass


class IntegrationRegistry:
    def __init__(self) -> None:
        self._lock = threading.Lock()
        self._integrations: Dict[str, Dict[str, Any]] = {}

    def register(self, name: str, *, default_headers: Optional[Dict[str, str]] = None, allowed_schemes: Optional[Iterable[str]] = None) -> None:
        if not name or not isinstance(name, str):
            raise ValueError("Integration name required")
        with self._lock:
            self._integrations[name] = {
                "default_headers": dict(default_headers or {}),
                "allowed_schemes": tuple(allowed_schemes) if allowed_schemes else _DEFAULT_ALLOWED_SCHEMES,
            }

    def get(self, name: str) -> Dict[str, Any]:
        with self._lock:
            if name not in self._integrations:
                raise KeyError(f"Unknown integration: {name}")
            return dict(self._integrations[name])


def display_url_content_interactive(
    registry: Optional[IntegrationRegistry] = None,
    *,
    integration_name: Optional[str] = None,
    print_headers: bool = False,
    max_chars: int = 8000,
) -> FetchResult:
    url = input("Enter URL: ").strip()
    headers: Dict[str, str] = {}
    allowed_schemes = _DEFAULT_ALLOWED_SCHEMES
    if registry and integration_name:
        cfg = registry.get(integration_name)
        headers.update(cfg.get("default_headers", {}) or {})
        allowed_schemes = cfg.get("allowed_schemes", _DEFAULT_ALLOWED_SCHEMES)

    result = fetch_url_content(url, headers=headers, allowed_schemes=allowed_schemes)

    if result.error:
        print(f"Error fetching {result.url}: {result.error}")
        return result

    print(f"URL: {result.url}")
    print(f"Status: {result.status_code}")
    print(f"Elapsed: {result.elapsed_ms}ms")
    if print_headers:
        for k, v in sorted(result.headers.items(), key=lambda kv: kv[0].lower()):
            print(f"{k}: {v}")
        print("")

    body = result.text
    if max_chars is not None and max_chars >= 0 and len(body) > max_chars:
        body = body[:max_chars] + "\n\n[truncated]"
    print(body)
    return result


def lambda_handler(event: Dict[str, Any], context: Any = None) -> Dict[str, Any]:
    integration = (event or {}).get("integration") or (event or {}).get("integration_name")
    url = (event or {}).get("url")
    if not url:
        return {"ok": False, "error": "Missing url", "statusCode": 400}

    reg = IntegrationRegistry()
    try:
        integrations_env = os.getenv("INTEGRATIONS_CONFIG_JSON", "").strip()
        if integrations_env:
            cfg = json.loads(integrations_env)
            if isinstance(cfg, dict):
                for name, icfg in cfg.items():
                    if isinstance(icfg, dict):
                        reg.register(
                            name,
                            default_headers=icfg.get("default_headers") or {},
                            allowed_schemes=icfg.get("allowed_schemes") or _DEFAULT_ALLOWED_SCHEMES,
                        )
    except Exception:
        pass

    headers = {}
    allowed_schemes = _DEFAULT_ALLOWED_SCHEMES
    if integration:
        try:
            icfg = reg.get(str(integration))
            headers.update(icfg.get("default_headers", {}) or {})
            allowed_schemes = icfg.get("allowed_schemes", _DEFAULT_ALLOWED_SCHEMES)
        except Exception:
            pass

    result = fetch_url_content(
        url,
        headers=headers,
        allowed_schemes=allowed_schemes,
        max_bytes=int(os.getenv("FETCH_MAX_BYTES", str(_DEFAULT_MAX_BYTES))),
        verify_tls=os.getenv("VERIFY_TLS", "true").lower() != "false",
    )

    if result.error:
        return {
            "ok": False,
            "error": result.error,
            "url": result.url,
            "statusCode": 502,
        }

    content_type = result.headers.get("Content-Type", "")
    return {
        "ok": True,
        "url": result.url,
        "status": result.status_code,
        "content_type": content_type,
        "elapsed_ms": result.elapsed_ms,
        "headers": result.headers,
        "body": result.text,
        "statusCode": 200,
    }